def pw(x, y):
    if y == 0:
        return 1
    res = pw(x, y//2)
    res = res * res % M
    if y % 2 == 1:
        res = res * x % M
    return res

def cal(x, y):
    y += x - 1
    res = 1
    for i in range(1, x + 1):
        res = res * (y - i + 1)
        res = res * pw(i, M - 2) % M
    return res % M

