class DSU:

    def __init__(self):
        self.parent = None
        self.has_zero = False
        self.has_one = False
        self.size = 1
        self.doors = []

    def get_root(self):
        if self.parent is None:
            return self
        self.parent = self.parent.get_root()
        return self.parent

    def unite(self, s):
        r1 = self.get_root()
        r2 = s.get_root()

        if r1 is r2:
            return r1

        if r1.size < r2.size:
            r1, r2 = r2, r1

        r2.parent = r1
        r1.size += r2.size
        r1.has_zero = r1.has_zero or r2.has_zero
        r1.has_one = r1.has_one or r2.has_one

        return r1

