def all_primes(n):
    res = []
    for i in range(1, n+1):
        prime = True
        for j in range(2, min(int(sqrt(i))+2, i)):
            if i % j == 0:
                prime = False
                break
        if prime: res.append(i)
    return res


def count_pow_nums(n, p):  #don't count 1
    top = int(pow(n, 1.0/p))
    if pow(top+2, p) <= n:
        return top+1
    elif pow(top+1, p) <= n:
        return top
    elif pow(top, p) <= n:
        return top-1
    else:
        return top-2
