    descendants = [[] for i in range(n)]
    for i in range(n - 1):
        descendants[ancestors[i]].append(i + 1)
    color = [None for i in range(n)]
    for i in range(n):
        if not descendants[i]:
            color[i] = True
            coloring(i, ancestors, color)
    reds = 0
    blues = 0
    xor = 0
    count_red = dict()
    count_blue = dict()
    for i in range(n):
        if color[i]:
            blues += 1
            xor ^= a[i]
