                count_blue[str(a[i])] += 1
            else:
                count_blue[str(a[i])] = 1
        else:
            reds += 1
            if str(a[i]) in count_red:
                count_red[str(a[i])] += 1
            else:
                count_red[str(a[i])] = 1
    res = 0
