import sys
import math

def sieve(n):
    prime_factors = [[] for i in range(n+1)]
    tmp = [True] * (n+1)
    tmp[0] = tmp[1] = False
    for i in range(2, n+1):
        if tmp[i]:
            for k in range(i, n+1, i):
                tmp[k] = False
                prime_factors[k].append(i)
    return prime_factors

